var model, fileHandler, loaded = {};

module.exports = function(dbConfig, storeConfig) {

  model = require('./model')(dbConfig);

  if (storeConfig) fileHandler = require('./s3')(storeConfig);

  return {
    events: loader('events'),
    locations: loader('locations'),
    reviews: loader('reviews'),
    reviewCredentials: loader('reviewCredentials'),
    users: loader('users'),
    tokens: loader('tokens'),
    endConnection: model.endConnection
  };

};

var loader = function(name) {

  return function() {

    if (!loaded[name]) {

      loaded[name] = require('./' + name)(model, fileHandler);

    }

    return loaded[name];
  };

};